fd，现在予以修复。

Signed-off-by: yinjiaming <yinjiaming@huawei.com>
Change-Id: I79f96880c6544d9548dcb1dd33b287981c18c0a9
[SEP] int getifaddrs(struct ifaddrs **ifap)
 	if ((fd = socket(AF_INET, SOCK_DGRAM | SOCK_CLOEXEC, 0)) < 0) 
 		return -1;
 	if (ioctl(fd, SIOCGIFCONF, &ifconfig) < 0)
-		goto error;
+		goto exit;
 	if (ifconfig.ifc_len % sizeof(struct ifreq)) {
 		errno = EINVAL;
-		goto error;
+		goto exit;
 	}
 	ifno = ifconfig.ifc_len / sizeof(struct ifreq);

 	if (!(ifstart = ifaddrs_init())) {
 		errno = ENOMEM;
-		goto error;
+		goto exit;
 	}
 	struct ifaddrs *ifa = ifstart;

[EOS]

