        return -1;
    }
    (void)memset_s(ifc.ifc_buf, nbytes, 0, nbytes);

    ret = lwip_ioctl(sockfd, cmd, &ifc);
    if (ret == 0) {
        if (LOS_ArchCopyToUser(buf_bak, ifc.ifc_buf, nbytes) != 0) {
            set_errno(EFAULT);
            ret = -1;
        }
    }

    free(ifc.ifc_buf);
    ifc.ifc_buf = buf_bak;
    if (LOS_ArchCopyToUser(argp, &ifc, sizeof(struct ifconf)) != 0) {
        set_errno(EFAULT);
        ret = -1;
    }
    return ret;
}

